        "status": "error",
        "message": "Missing challengeId"
      },
      "args": [],
      "kwargs": {},
      "notes": "Submission without a challenge ID should return an error."
    },
    {
      "name": "unsupported_language",
      "input": {
        "challengeId": "12345",
        "submissionData": {
          "code": "print('Hello World')",
          "language": "Python"
        }
      },
      "output": {
        "status": "error",
        "message": "Unsupported language"
      },
      "args": [],
      "kwargs": {},
      "notes": "Submission in an unsupported language should return an error."
    },
    {
      "name": "high_load_submission",
      "input": {
        "challengeId": "12345",
        "submissionData": {
          "code": "for(int i=0; i<1000000; i++);"
        }
      },
      "output": {
        "status": "success",
        "score": 80
      },
      "args": [],
      "kwargs": {},
      "notes": "High load submission should be processed successfully but may receive a lower score."
    },
    {
      "name": "malicious_code_submission",
      "input": {
        "challengeId": "12345",
        "submissionData": {
          "code": "System.exit(1);"
        }
      },
      "output": {
        "status": "error",
        "message": "Malicious code detected"
      },
      "args": [],
      "kwargs": {},
      "notes": "Submission containing malicious code should be flagged and return an error."
    },
